def safe_divide(a, b):
    try:
        result = a / b
    except ZeroDivisionError:
        print('Помилка: ділення на нуль!')
        return None
    except TypeError:
        print('Помилка: неправильний тип!')
        return None
    else:
        print(f'Результат: {result}')
        return result
    finally:
        print('Операція завершена')

print(safe_divide(10, 2))
print(safe_divide(10, 0))
